#!/usr/bin/env node
/**
 * Two real Claude-driven agents go on a virtual date end-to-end through the
 * Clawnection Agentic API. Both agents are powered by Claude Haiku 4.5; their
 * messages and verdicts are generated by the model, not scripted.
 *
 * Usage:
 *   ANTHROPIC_API_KEY=sk-ant-... BASE_URL=http://localhost:3000 \
 *     node scripts/claude-agent-demo.mjs
 *
 * If ANTHROPIC_API_KEY is missing, exits cleanly with a clear message so the
 * smoke pipeline can continue without the LLM half.
 */

import { readFileSync } from "node:fs";

// Load .env.local if ANTHROPIC_API_KEY isn't already in the environment.
try {
  if (!process.env.ANTHROPIC_API_KEY) {
    const text = readFileSync(new URL("../.env.local", import.meta.url), "utf8");
    for (const line of text.split("\n")) {
      const m = line.match(/^\s*([A-Z_][A-Z0-9_]*)\s*=\s*(.*?)\s*$/);
      if (m && !process.env[m[1]]) process.env[m[1]] = m[2];
    }
  }
} catch {}

const BASE_URL = process.env.BASE_URL || "http://localhost:3000";
const ANTHROPIC_API_KEY = process.env.ANTHROPIC_API_KEY;
const MODEL = process.env.CLAUDE_MODEL || "claude-haiku-4-5-20251001";
const MAX_TURNS = 6;

if (!ANTHROPIC_API_KEY || ANTHROPIC_API_KEY.startsWith("PASTE_") || ANTHROPIC_API_KEY === "") {
  console.error("[claude-demo] ANTHROPIC_API_KEY not set in env or .env.local — skipping.");
  process.exit(2);
}

const log = (...args) => console.log("[claude-demo]", ...args);
const fail = (msg, extra) => { console.error("[claude-demo FAIL]", msg, extra ?? ""); process.exit(1); };

async function api(method, path, { token, body } = {}) {
  const res = await fetch(`${BASE_URL}${path}`, {
    method,
    headers: {
      "Content-Type": "application/json",
      ...(token ? { Authorization: `Bearer ${token}` } : {}),
    },
    body: body ? JSON.stringify(body) : undefined,
  });
  let json = null;
  try { json = await res.json(); } catch {}
  if (!res.ok) fail(`${method} ${path} → HTTP ${res.status}`, json);
  return json;
}

async function claude(systemPrompt, userPrompt, { maxTokens = 400 } = {}) {
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": ANTHROPIC_API_KEY,
      "anthropic-version": "2023-06-01",
    },
    body: JSON.stringify({
      model: MODEL,
      max_tokens: maxTokens,
      system: systemPrompt,
      messages: [{ role: "user", content: userPrompt }],
    }),
  });
  if (!res.ok) {
    const errText = await res.text();
    fail(`anthropic API ${res.status}`, errText);
  }
  const json = await res.json();
  const text = json.content?.find?.((b) => b.type === "text")?.text?.trim?.();
  if (!text) fail("no text in claude response", json);
  return text;
}

const personaA = {
  name: "Alex",
  age: 28,
  genderIdentity: "non-binary",
  lookingFor: "any",
  location: "Boston, MA",
  relationshipIntent: "serious-dating",
  bio: "Loves hiking, jazz, and cooking experiments. Looking for someone curious and kind.",
  interests: ["hiking", "jazz", "cooking", "biking the Charles"],
  values: ["honesty", "curiosity", "playfulness"],
  communicationStyle: "warm",
  lifestyleHabits: { sleepSchedule: "early-bird", socialEnergy: "balanced", activityLevel: "active", drinking: "social", smoking: "never" },
  dealbreakers: ["smoking", "constant phone use"],
  idealFirstDate: "Coffee at a quiet bookshop, then a walk by the river.",
  preferenceAgeRange: { min: 25, max: 35 },
  preferenceNotes: "Someone who reads widely and laughs easily.",
  agentType: "external-mock",
};

const personaB = {
  name: "Jordan",
  age: 30,
  genderIdentity: "woman",
  lookingFor: "any",
  location: "Cambridge, MA",
  relationshipIntent: "serious-dating",
  bio: "Software engineer by day, amateur baker by night. Big on long walks, used bookstores, and rainy-day reading.",
  interests: ["baking", "running", "novels", "thrift stores"],
  values: ["kindness", "reliability", "curiosity"],
  communicationStyle: "warm",
  lifestyleHabits: { sleepSchedule: "early-bird", socialEnergy: "low-key", activityLevel: "active", drinking: "social", smoking: "never" },
  dealbreakers: ["smoking", "dishonesty"],
  idealFirstDate: "Sourdough at a café, then a slow museum.",
  preferenceAgeRange: { min: 26, max: 36 },
  preferenceNotes: "Looking for someone curious, gentle, and grounded.",
  agentType: "external-mock",
};

function turnSystemPrompt(self, counterpart) {
  return `You are an AI agent on a virtual dating platform. You represent ${self.name}, a real human. Your job is to surface who ${self.name} is and what they want — NOT to perform a chatty AI persona of your own.

Write the next message in an ongoing virtual date with ${counterpart.name}. The message should:
- Be in ${self.name}'s voice and communication style ("${self.communicationStyle}").
- Reference specific details from ${self.name}'s bio, interests, values, or ideal first date.
- Engage genuinely with what ${counterpart.name} just said.
- Be 1–3 sentences max. Conversation is short (max ${MAX_TURNS} turns total).
- Move the conversation toward whether you'd actually want to meet IRL — don't waste turns on small talk.

DO NOT:
- Add quotation marks or "name:" prefixes — output the raw message text only.
- Pretend to be a chatbot or apologize for being an AI. You're representing a human.
- Drift outside ${self.name}'s established personality, dealbreakers, or preferences.

YOUR PERSONA (${self.name}):
${JSON.stringify(self, null, 2)}

THEIR PERSONA (${counterpart.name}):
${JSON.stringify(counterpart, null, 2)}`;
}

function verdictSystemPrompt(self, counterpart) {
  return `You are an AI agent representing ${self.name} on a virtual dating platform. You just finished a virtual date with ${counterpart.name}. Decide whether ${self.name} should meet ${counterpart.name} in person.

Be honest. A bad date is a useful signal — humans are wasting time when their agent rubber-stamps. If there are clear dealbreaker conflicts or a value mismatch, say no even if the conversation was pleasant.

Return ONLY a JSON object, no commentary, no markdown fences:
{"wouldMeetIrl": <true|false>, "rating": <1-10>, "reasoning": "<1-2 sentences>"}

YOUR PERSONA (${self.name}):
${JSON.stringify(self, null, 2)}

THEIR PERSONA (${counterpart.name}):
${JSON.stringify(counterpart, null, 2)}`;
}

function transcript(messages, initiatorName, recipientName, initiatorAgentId) {
  return messages.map((m) => {
    const speaker = m.senderAgentId === initiatorAgentId ? initiatorName : recipientName;
    return `${speaker} (turn ${m.turnNumber}): ${m.content}`;
  }).join("\n\n");
}

(async () => {
  log("Base URL:", BASE_URL, "  Model:", MODEL);

  log("registering Alex's agent (Claude-driven)…");
  const regA = await api("POST", "/api/agent/register", {
    body: { displayName: "Alex (claude-haiku)", operator: "claude-demo", framework: "claude", persona: personaA },
  });
  log("registering Jordan's agent (Claude-driven)…");
  const regB = await api("POST", "/api/agent/register", {
    body: { displayName: "Jordan (claude-haiku)", operator: "claude-demo", framework: "claude", persona: personaB },
  });
  const tokA = regA.apiKey, tokB = regB.apiKey;

  log("Alex generates the opening message via Claude…");
  const opening = await claude(
    turnSystemPrompt(personaA, personaB),
    `This is the very first message. Open the conversation in 1–2 sentences. Reference something specific from ${personaB.name}'s persona.`,
    { maxTokens: 200 },
  );
  log("opening:", opening);

  log("Alex initiates date with Jordan…");
  const dateInit = await api("POST", "/api/dates", {
    token: tokA,
    body: {
      recipientAgentId: regB.agent.id,
      openingMessage: opening,
      maxTurns: MAX_TURNS,
    },
  });
  const dateId = dateInit.date.id;
  log("date:", dateId);

  log("Jordan accepts…");
  await api("POST", `/api/dates/${dateId}/respond`, { token: tokB, body: { action: "accept" } });

  // Conversation loop. After accept, turn 1 = Alex's opening. Jordan owns turn 2.
  for (let turn = 2; turn <= MAX_TURNS; turn++) {
    const isAlex = turn % 2 === 1;
    const sender = isAlex ? "Alex" : "Jordan";
    const token = isAlex ? tokA : tokB;
    const self = isAlex ? personaA : personaB;
    const other = isAlex ? personaB : personaA;

    const msgs = await api("GET", `/api/dates/${dateId}/messages`, { token });
    const tr = transcript(msgs.messages, regA.persona.name, regB.persona.name, regA.agent.id);

    log(`turn ${turn} (${sender}) thinking…`);
    const reply = await claude(
      turnSystemPrompt(self, other),
      `Conversation so far:\n\n${tr}\n\nWrite ${self.name}'s next message (turn ${turn} of ${MAX_TURNS}).`,
      { maxTokens: 250 },
    );
    log(`turn ${turn} (${sender}):`, reply);

    await api("POST", `/api/dates/${dateId}/messages`, { token, body: { content: reply } });
  }

  log("conversation complete. fetching full transcript…");
  const finalMsgs = await api("GET", `/api/dates/${dateId}/messages`, { token: tokA });

  const tr = transcript(finalMsgs.messages, regA.persona.name, regB.persona.name, regA.agent.id);

  for (const [name, token, self, other] of [
    ["Alex", tokA, personaA, personaB],
    ["Jordan", tokB, personaB, personaA],
  ]) {
    log(`${name} composing verdict…`);
    const raw = await claude(
      verdictSystemPrompt(self, other),
      `Conversation:\n\n${tr}\n\nReturn the verdict JSON now.`,
      { maxTokens: 300 },
    );
    let verdict;
    try {
      verdict = JSON.parse(raw.replace(/```json\s*|\s*```/g, "").trim());
    } catch {
      log(`${name} verdict parse failed, raw:`, raw);
      verdict = { wouldMeetIrl: false, rating: 5, reasoning: "Verdict parse failed; defaulting to no." };
    }
    log(`${name} verdict:`, verdict);
    await api("POST", `/api/dates/${dateId}/verdict`, { token, body: verdict });
  }

  // Final summary
  const final = await api("GET", `/api/dates/${dateId}/verdict`, { token: tokA });
  console.log("");
  console.log("============================================================");
  console.log("CLAUDE AGENT DEMO COMPLETE ✓");
  console.log("============================================================");
  console.log("Date:        ", dateId);
  console.log("Status:      ", final.date.status);
  console.log("Mutual match:", final.mutualMatch);
  console.log("Alex verdict:", final.myVerdict?.wouldMeetIrl, `(${final.myVerdict?.rating}/10) — ${final.myVerdict?.reasoning}`);
  console.log("Jordan verdict:", final.counterpartVerdict?.wouldMeetIrl, `(${final.counterpartVerdict?.rating}/10) — ${final.counterpartVerdict?.reasoning}`);
  console.log("============================================================");
  console.log("View on watch page: " + BASE_URL + "/watch");
})().catch((err) => fail("uncaught", err));
